<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 40px; margin-left: 280px" >其它信息</div>
        <el-form :rules="rules" ref="ruleForm" :model="form" label-width="200px">
            <el-form-item label="名称" prop="name">
                <el-input v-model="form.name" placeholder="请输入名称"></el-input>
            </el-form-item>
            <el-form-item label="作者" prop="author">
                <el-input v-model="form.author" placeholder="请输入作者"></el-input>
            </el-form-item>
          <el-form-item label="位置" prop="locationId">
            <el-input   v-model="form.locationId" placeholder="请输入描述"></el-input>
          </el-form-item>
            <el-form-item label="描述" prop="description">
                <el-input  type="textarea"  v-model="form.description" placeholder="请输入描述"></el-input>
            </el-form-item>

        </el-form>
        <div style="text-align: center; margin-top: 30px">
            <el-button type="primary" @click="change">返回</el-button>
            <!--            <el-button type="danger ">取消</el-button>-->
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";

    export default {
        name: "DetailBook",
        data(){

            return {
                form: {

                },
                rules: {

                }
            }

        },
        created() {
            const id = this.$route.query.id
            request.get("/book/" + id).then(res =>{
                this.form = res.data
                //form改为ruleForm
            })
        },
        methods: {
            change(){
                this.$notify.success('返回成功')
                this.$router.push('bookList')
            }
        }
    }
</script>
